import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import assureurAPI from '../services/assureurAPI';
import './Assureur.css';

// ─── Helpers ──────────────────────────────────────────────────────────────────

const NIVEAU_COLORS = {
  low:      '#4DFFB4',
  medium:   '#FFB347',
  high:     '#FF8800',
  critical: '#FF4466',
};

const NIVEAU_LABELS = {
  low: 'Faible', medium: 'Modéré', high: 'Élevé', critical: 'Critique',
};

const STATUS_LABELS = {
  draft:       'Brouillon',
  soumis:      'Soumis',
  en_analyse:  'En analyse',
  analysé:     'Analysé',
  validé:      'Validé',
  rejeté:      'Rejeté',
  en_attente:  'En attente',
};

function RiskBadge({ niveau }) {
  if (!niveau) return <span className="asr-badge asr-badge--draft">—</span>;
  return (
    <span className={`asr-risk-badge asr-risk-badge--${niveau}`}>
      <span>●</span> {NIVEAU_LABELS[niveau] || niveau}
    </span>
  );
}

function StatusBadge({ status }) {
  const cls = status === 'en_analyse' ? 'en_analyse'
    : status === 'analysé' ? 'analyse'
    : status === 'en_attente' ? 'en_attente'
    : status || 'draft';
  return (
    <span className={`asr-badge asr-badge--${cls}`}>
      {STATUS_LABELS[status] || status || '—'}
    </span>
  );
}

function ScoreBar({ value, color }) {
  const pct = Math.min(100, Math.max(0, value || 0));
  return (
    <div className="asr-score-cell">
      <span className="asr-score-num" style={{ color: color || '#00D4FF' }}>
        {value != null ? value.toFixed(1) : '—'}
      </span>
      {value != null && (
        <div className="asr-score-bar-bg">
          <div
            className="asr-score-bar"
            style={{ width: `${pct}%`, background: color || NIVEAU_COLORS.medium }}
          />
        </div>
      )}
    </div>
  );
}

function formatDate(dt) {
  if (!dt) return '—';
  return new Date(dt).toLocaleDateString('fr-FR', {
    day: '2-digit', month: '2-digit', year: 'numeric',
  });
}

function formatDateTime(dt) {
  if (!dt) return '—';
  return new Date(dt).toLocaleString('fr-FR', {
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit',
  });
}

function formatPrime(v) {
  if (v == null) return '—';
  return new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'EUR' }).format(v);
}

// ─── Gauge SVG ────────────────────────────────────────────────────────────────

function ScoreGauge({ score, niveau }) {
  const r = 60, cx = 80, cy = 80;
  const circumference = Math.PI * r;           // semi-circle
  const pct = Math.min(100, Math.max(0, score || 0));
  const color = NIVEAU_COLORS[niveau] || '#00D4FF';
  const offset = circumference * (1 - pct / 100);

  return (
    <div className="asr-gauge-wrap">
      <span className="asr-gauge-label">Score moyen</span>
      <svg width="160" height="90" className="asr-gauge-svg" viewBox="0 0 160 90">
        {/* Track */}
        <path
          d={`M 20 80 A 60 60 0 0 1 140 80`}
          fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="10"
          strokeLinecap="round"
        />
        {/* Fill */}
        <path
          d={`M 20 80 A 60 60 0 0 1 140 80`}
          fill="none"
          stroke={color}
          strokeWidth="10"
          strokeLinecap="round"
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          style={{ transition: 'stroke-dashoffset 1s ease, stroke 0.5s' }}
          filter={`drop-shadow(0 0 6px ${color}60)`}
        />
        {/* Score text */}
        <text x="80" y="72" textAnchor="middle" fill={color}
          fontSize="22" fontWeight="700" fontFamily="JetBrains Mono, monospace">
          {score ? score.toFixed(1) : '—'}
        </text>
      </svg>
      <span
        className="asr-gauge-sub"
        style={{ color, background: `${color}15`, border: `1px solid ${color}30` }}
      >
        {NIVEAU_LABELS[niveau] || (score ? 'En calcul' : 'Aucun score')}
      </span>
    </div>
  );
}

// ─── Accordion ────────────────────────────────────────────────────────────────

function Accordion({ title, children, defaultOpen = false }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="asr-accordion">
      <button className="asr-accordion-head" onClick={() => setOpen(o => !o)}>
        <span>{title}</span>
        <span className={`asr-accordion-arrow ${open ? 'asr-accordion-arrow--open' : ''}`}>▼</span>
      </button>
      {open && <div className="asr-accordion-body">{children}</div>}
    </div>
  );
}

// ─── Detail Side Panel ────────────────────────────────────────────────────────

function DossierPanel({ dossier, onClose }) {
  const score = dossier.score;
  const devis = dossier.devis;
  const entreprise = dossier.entreprise || {};
  const scoreColor = score ? (NIVEAU_COLORS[score.niveau_risque] || '#00D4FF') : '#00D4FF';

  // Group réponses by catégorie
  const groupedReponses = (dossier.reponses || []).reduce((acc, r) => {
    const cat = r.categorie || 'Général';
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(r);
    return acc;
  }, {});

  return (
    <>
      <div className="asr-overlay" onClick={onClose} />
      <aside className="asr-panel">
        <div className="asr-panel-header">
          <div>
            <div className="asr-panel-title">
              Dossier #{dossier.id_dossier} — {entreprise.nom || '—'}
            </div>
            <div className="asr-panel-sub">
              Soumis par {dossier.courtier_email} · {formatDateTime(dossier.date_soumission)}
            </div>
          </div>
          <button className="asr-panel-close" onClick={onClose}>✕</button>
        </div>

        <div className="asr-panel-body">

          {/* Entreprise */}
          <div className="asr-detail-section">
            <div className="asr-detail-section-header">
              <span className="asr-detail-section-icon">🏢</span>
              <span className="asr-detail-section-title">Entreprise</span>
            </div>
            <div className="asr-detail-grid">
              <div className="asr-detail-field">
                <span className="asr-detail-field-label">Nom</span>
                <span className="asr-detail-field-value">{entreprise.nom || '—'}</span>
              </div>
              <div className="asr-detail-field">
                <span className="asr-detail-field-label">Secteur</span>
                <span className="asr-detail-field-value">{entreprise.secteur || '—'}</span>
              </div>
              <div className="asr-detail-field">
                <span className="asr-detail-field-label">Taille</span>
                <span className="asr-detail-field-value">{entreprise.taille || '—'}</span>
              </div>
              <div className="asr-detail-field">
                <span className="asr-detail-field-label">Status dossier</span>
                <span className="asr-detail-field-value"><StatusBadge status={dossier.status} /></span>
              </div>
            </div>
          </div>

          {/* Score */}
          {score ? (
            <div className="asr-detail-section">
              <div className="asr-detail-section-header">
                <span className="asr-detail-section-icon">📊</span>
                <span className="asr-detail-section-title">Score de risque</span>
                <RiskBadge niveau={score.niveau_risque} />
              </div>
              <div className="asr-score-panel">
                <div className="asr-score-row">
                  <span className="asr-score-row-label">Score questionnaire</span>
                  <div className="asr-score-row-bar">
                    <div className="asr-score-row-bar-fill"
                      style={{ width: `${score.score_questionnaire}%`, background: '#00D4FF' }} />
                  </div>
                  <span className="asr-score-row-val" style={{ color: '#00D4FF' }}>
                    {score.score_questionnaire?.toFixed(1)}
                  </span>
                </div>
                <div className="asr-score-row">
                  <span className="asr-score-row-label">Score documents</span>
                  <div className="asr-score-row-bar">
                    <div className="asr-score-row-bar-fill"
                      style={{ width: `${score.score_document}%`, background: '#9B8FFF' }} />
                  </div>
                  <span className="asr-score-row-val" style={{ color: '#9B8FFF' }}>
                    {score.score_document?.toFixed(1)}
                  </span>
                </div>
              </div>
              <div className="asr-score-total">
                <span className="asr-score-total-label">Score global</span>
                <span className="asr-score-total-val" style={{ color: scoreColor }}>
                  {score.score_global?.toFixed(1)} / 100
                </span>
              </div>
            </div>
          ) : (
            <div className="asr-detail-section">
              <div className="asr-empty">
                <span className="asr-empty-icon">📊</span>
                <span className="asr-empty-text">Aucun score calculé</span>
                <span className="asr-empty-sub">L'analyse IA n'a pas encore été effectuée</span>
              </div>
            </div>
          )}

          {/* Devis */}
          {devis ? (
            <div className="asr-detail-section">
              <div className="asr-detail-section-header">
                <span className="asr-detail-section-icon">📋</span>
                <span className="asr-detail-section-title">Devis</span>
                <StatusBadge status={devis.status} />
              </div>
              <div className="asr-detail-grid">
                <div className="asr-detail-field">
                  <span className="asr-detail-field-label">Prime proposée</span>
                  <span className="asr-detail-field-value" style={{ color: '#00D4FF', fontSize: 18, fontWeight: 700 }}>
                    {formatPrime(devis.prime)}
                  </span>
                </div>
                <div className="asr-detail-field">
                  <span className="asr-detail-field-label">Créé le</span>
                  <span className="asr-detail-field-value">{formatDate(devis.created_at)}</span>
                </div>
              </div>
            </div>
          ) : null}

          {/* Questionnaire réponses */}
          {Object.keys(groupedReponses).length > 0 ? (
            <div className="asr-detail-section">
              <div className="asr-detail-section-header">
                <span className="asr-detail-section-icon">📝</span>
                <span className="asr-detail-section-title">
                  Questionnaire ({dossier.reponses?.length} réponses)
                </span>
              </div>
              {Object.entries(groupedReponses).map(([cat, reps]) => (
                <Accordion key={cat} title={`${cat} (${reps.length})`} defaultOpen={cat === 'Général'}>
                  {reps.map(r => (
                    <div key={r.id_reponse} className="asr-reponse-item">
                      <span className="asr-reponse-q">{r.question_texte}</span>
                      <span className="asr-reponse-a">{r.valeur || '—'}</span>
                    </div>
                  ))}
                </Accordion>
              ))}
            </div>
          ) : (
            <div className="asr-detail-section">
              <div className="asr-empty">
                <span className="asr-empty-icon">📝</span>
                <span className="asr-empty-text">Aucune réponse au questionnaire</span>
              </div>
            </div>
          )}

          {/* Documents */}
          <div className="asr-detail-section">
            <div className="asr-detail-section-header">
              <span className="asr-detail-section-icon">📁</span>
              <span className="asr-detail-section-title">
                Documents ({dossier.documents?.length || 0})
              </span>
            </div>
            {dossier.documents?.length > 0 ? (
              <div className="asr-docs-list">
                {dossier.documents.map(doc => (
                  <div key={doc.id_document} className="asr-doc-item">
                    <div className="asr-doc-icon">📄</div>
                    <div className="asr-doc-info">
                      <span className="asr-doc-type">{doc.type || 'Document'}</span>
                      <span className="asr-doc-date">{formatDateTime(doc.uploaded_at)}</span>
                      {doc.nb_analyses > 0 && (
                        <span className="asr-doc-analyses">✓ {doc.nb_analyses} analyse(s) IA</span>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="asr-empty">
                <span className="asr-empty-icon">📁</span>
                <span className="asr-empty-text">Aucun document</span>
              </div>
            )}
          </div>

          {/* Analyses IA */}
          {dossier.analyses?.length > 0 && (
            <div className="asr-detail-section">
              <div className="asr-detail-section-header">
                <span className="asr-detail-section-icon">🤖</span>
                <span className="asr-detail-section-title">
                  Analyses IA ({dossier.analyses.length})
                </span>
              </div>
              {dossier.analyses.map(a => (
                <div key={a.id_analyse} className="asr-analyse-item">
                  <div className="asr-analyse-top">
                    <span className="asr-analyse-model">
                      {a.modele_utilise || 'Modèle IA'} · {a.document_type || 'Document'}
                    </span>
                    {a.confidence != null && (
                      <span className="asr-analyse-confidence">
                        {(a.confidence * 100).toFixed(0)}% confiance
                      </span>
                    )}
                  </div>
                  {a.resultat && (
                    <div className="asr-analyse-result">
                      {typeof a.resultat === 'string'
                        ? a.resultat
                        : JSON.stringify(a.resultat, null, 2)}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}

        </div>
      </aside>
    </>
  );
}

// ─── Confirm Modal ────────────────────────────────────────────────────────────

function ConfirmModal({ icon, title, text, confirmLabel, confirmClass, onConfirm, onCancel }) {
  return (
    <div className="asr-modal-overlay">
      <div className="asr-modal">
        <div className="asr-modal-icon">{icon}</div>
        <div className="asr-modal-title">{title}</div>
        <div className="asr-modal-text">{text}</div>
        <div className="asr-modal-actions">
          <button className="asr-btn asr-btn--ghost" onClick={onCancel}>Annuler</button>
          <button className={`asr-btn ${confirmClass}`} onClick={onConfirm}>{confirmLabel}</button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// TABS
// ═══════════════════════════════════════════════════════════════════════════════

// ─── Tab 1 : Vue d'ensemble ───────────────────────────────────────────────────

function TabOverview({ stats, onTabChange }) {
  if (!stats) return <div className="asr-loading"><div className="asr-spinner" /><span>Chargement…</span></div>;

  const repartition = stats.repartition_risque || {};
  const totalRisk = Object.values(repartition).reduce((s, v) => s + v, 0);

  const riskLevels = [
    { key: 'low',      label: 'Faible',   color: '#4DFFB4' },
    { key: 'medium',   label: 'Modéré',   color: '#FFB347' },
    { key: 'high',     label: 'Élevé',    color: '#FF8800' },
    { key: 'critical', label: 'Critique', color: '#FF4466' },
  ];

  const topNiveau = riskLevels.reduce((top, r) =>
    (repartition[r.key] || 0) > (repartition[top.key] || 0) ? r : top,
    riskLevels[0]
  );

  const statCards = [
    { label: 'Dossiers reçus',  value: stats.dossiers_recus,      icon: '📁', color: '#00D4FF', sub: 'Total soumis' },
    { label: 'En attente',      value: stats.dossiers_en_attente, icon: '⏳', color: '#FFB347', sub: 'À traiter' },
    { label: 'Devis à valider', value: stats.devis_a_valider,     icon: '📋', color: '#9B8FFF', sub: 'En attente validation' },
    { label: 'Validés',         value: stats.devis_valides,       icon: '✅', color: '#4DFFB4', sub: 'Devis acceptés' },
    { label: 'Rejetés',         value: stats.devis_rejetes,       icon: '❌', color: '#FF4466', sub: 'Devis refusés' },
  ];

  return (
    <div>
      {/* Stats */}
      <div className="asr-stats">
        {statCards.map((s, i) => (
          <div
            key={i} className="asr-stat"
            style={{ '--stat-color': s.color, animationDelay: `${i * 0.07}s` }}
          >
            <div className="asr-stat-top">
              <span className="asr-stat-label">{s.label}</span>
              <span className="asr-stat-icon">{s.icon}</span>
            </div>
            <span className="asr-stat-value">{s.value ?? '—'}</span>
            <span className="asr-stat-sub">{s.sub}</span>
          </div>
        ))}
      </div>

      {/* Score & Répartition */}
      <div className="asr-section">
        <div className="asr-section-header">
          <h2 className="asr-section-title">Analyse des risques</h2>
          <span className="asr-section-count">{totalRisk} dossiers scorés</span>
        </div>
        <div className="asr-risque-grid">
          <ScoreGauge score={stats.score_moyen} niveau={topNiveau?.key} />
          <div style={{ padding: '10px 0' }}>
            <div className="asr-repartition">
              {riskLevels.map(r => {
                const count = repartition[r.key] || 0;
                const pct = totalRisk > 0 ? Math.round((count / totalRisk) * 100) : 0;
                return (
                  <div key={r.key} className="asr-risk-row">
                    <div className="asr-risk-info">
                      <span className="asr-risk-name">
                        <span className="asr-risk-dot" style={{ background: r.color }} />
                        {r.label}
                      </span>
                      <span className="asr-risk-count">{count}</span>
                    </div>
                    <div className="asr-risk-bar-bg">
                      <div className="asr-risk-bar-fill"
                        style={{ width: `${pct}%`, background: r.color }} />
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Derniers dossiers */}
      <div className="asr-section">
        <div className="asr-section-header">
          <h2 className="asr-section-title">Derniers dossiers soumis</h2>
          <button className="asr-btn asr-btn--ghost" onClick={() => onTabChange('dossiers')}>
            Voir tous →
          </button>
        </div>
        {stats.derniers_dossiers?.length > 0 ? (
          <div className="asr-table-wrap">
            <table className="asr-table">
              <thead>
                <tr>
                  <th>Entreprise</th>
                  <th>Secteur</th>
                  <th>Soumis le</th>
                  <th>Score</th>
                  <th>Risque</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {stats.derniers_dossiers.map(d => (
                  <tr key={d.id_dossier}>
                    <td style={{ fontWeight: 600 }}>{d.entreprise_nom}</td>
                    <td style={{ color: 'var(--c-text2)' }}>{d.entreprise_secteur || '—'}</td>
                    <td style={{ color: 'var(--c-text2)', fontFamily: 'var(--f-mono)', fontSize: 12 }}>
                      {formatDate(d.date_soumission)}
                    </td>
                    <td><ScoreBar value={d.score_global} color={NIVEAU_COLORS[d.niveau_risque]} /></td>
                    <td><RiskBadge niveau={d.niveau_risque} /></td>
                    <td><StatusBadge status={d.status} /></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="asr-empty">
            <span className="asr-empty-icon">📭</span>
            <span className="asr-empty-text">Aucun dossier soumis</span>
            <span className="asr-empty-sub">Les dossiers des courtiers apparaîtront ici</span>
          </div>
        )}
      </div>

      {/* Alert devis */}
      {stats.devis_a_valider > 0 && (
        <div className="asr-section" style={{ borderColor: 'rgba(255,179,71,0.3)', background: 'rgba(255,179,71,0.04)' }}>
          <div className="asr-section-header">
            <h2 className="asr-section-title" style={{ color: '#FFB347' }}>
              ⚠ {stats.devis_a_valider} devis en attente de validation
            </h2>
            <button className="asr-btn asr-btn--primary" onClick={() => onTabChange('devis')}>
              Traiter maintenant
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── Tab 2 : Dossiers ─────────────────────────────────────────────────────────

function TabDossiers() {
  const [loading, setLoading] = useState(true);
  const [dossiers, setDossiers] = useState([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(0);
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [filterRisque, setFilterRisque] = useState('');
  const [selectedDossier, setSelectedDossier] = useState(null);
  const [loadingDetail, setLoadingDetail] = useState(false);
  const LIMIT = 15;

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await assureurAPI.getDossiers({
        skip: page * LIMIT, limit: LIMIT,
        ...(search && { search }),
        ...(filterStatus && { status: filterStatus }),
        ...(filterRisque && { niveau_risque: filterRisque }),
      });
      setDossiers(res.data.dossiers || []);
      setTotal(res.data.total || 0);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [page, search, filterStatus, filterRisque]);

  useEffect(() => { load(); }, [load]);

  const handleRowClick = async (id) => {
    setLoadingDetail(true);
    try {
      const res = await assureurAPI.getDossierDetail(id);
      setSelectedDossier(res.data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingDetail(false);
    }
  };

  const totalPages = Math.ceil(total / LIMIT);

  return (
    <div>
      <div className="asr-section">
        <div className="asr-section-header">
          <h2 className="asr-section-title">Dossiers reçus</h2>
          <span className="asr-section-count">{total} dossier{total > 1 ? 's' : ''}</span>
        </div>

        {/* Filters */}
        <div className="asr-filters">
          <div className="asr-search">
            <span className="asr-search-icon">🔍</span>
            <input
              type="text"
              placeholder="Rechercher une entreprise…"
              value={search}
              onChange={e => { setSearch(e.target.value); setPage(0); }}
            />
          </div>
          <select
            className="asr-filter-select"
            value={filterStatus}
            onChange={e => { setFilterStatus(e.target.value); setPage(0); }}
          >
            <option value="">Tous les status</option>
            <option value="soumis">Soumis</option>
            <option value="en_analyse">En analyse</option>
            <option value="analysé">Analysé</option>
          </select>
          <select
            className="asr-filter-select"
            value={filterRisque}
            onChange={e => { setFilterRisque(e.target.value); setPage(0); }}
          >
            <option value="">Tous les niveaux</option>
            <option value="low">Faible</option>
            <option value="medium">Modéré</option>
            <option value="high">Élevé</option>
            <option value="critical">Critique</option>
          </select>
          {(search || filterStatus || filterRisque) && (
            <button className="asr-btn asr-btn--ghost" onClick={() => {
              setSearch(''); setFilterStatus(''); setFilterRisque(''); setPage(0);
            }}>✕ Effacer</button>
          )}
        </div>

        {/* Table */}
        {loading ? (
          <div className="asr-loading"><div className="asr-spinner" /><span>Chargement…</span></div>
        ) : (
          <div className="asr-table-wrap">
            <table className="asr-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Entreprise</th>
                  <th>Secteur</th>
                  <th>Courtier</th>
                  <th>Soumis le</th>
                  <th>Score</th>
                  <th>Risque</th>
                  <th>Devis</th>
                  <th>Status</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {dossiers.length === 0 ? (
                  <tr>
                    <td colSpan={10} className="asr-table-empty">
                      Aucun dossier trouvé
                    </td>
                  </tr>
                ) : dossiers.map(d => (
                  <tr key={d.id_dossier} onClick={() => handleRowClick(d.id_dossier)}>
                    <td style={{ fontFamily: 'var(--f-mono)', fontSize: 12, color: 'var(--c-text2)' }}>
                      #{d.id_dossier}
                    </td>
                    <td style={{ fontWeight: 600 }}>{d.entreprise_nom}</td>
                    <td style={{ color: 'var(--c-text2)' }}>{d.entreprise_secteur || '—'}</td>
                    <td style={{ color: 'var(--c-text2)', fontSize: 12 }}>{d.courtier_email}</td>
                    <td style={{ fontFamily: 'var(--f-mono)', fontSize: 12, color: 'var(--c-text2)' }}>
                      {formatDate(d.date_soumission)}
                    </td>
                    <td>
                      <ScoreBar value={d.score_global} color={NIVEAU_COLORS[d.niveau_risque]} />
                    </td>
                    <td><RiskBadge niveau={d.niveau_risque} /></td>
                    <td>
                      {d.prime != null ? (
                        <span style={{ fontFamily: 'var(--f-mono)', fontSize: 12, color: '#00D4FF' }}>
                          {formatPrime(d.prime)}
                        </span>
                      ) : <span style={{ color: 'var(--c-text3)' }}>—</span>}
                    </td>
                    <td><StatusBadge status={d.status} /></td>
                    <td>
                      <button
                        className="asr-btn asr-btn--primary"
                        onClick={e => { e.stopPropagation(); handleRowClick(d.id_dossier); }}
                        disabled={loadingDetail}
                      >
                        Voir →
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="asr-pagination">
            <span>{page * LIMIT + 1}–{Math.min((page + 1) * LIMIT, total)} sur {total}</span>
            <div className="asr-pagination-btns">
              <button
                className="asr-btn asr-btn--ghost"
                onClick={() => setPage(p => p - 1)}
                disabled={page === 0}
              >← Préc.</button>
              <button
                className="asr-btn asr-btn--ghost"
                onClick={() => setPage(p => p + 1)}
                disabled={page >= totalPages - 1}
              >Suiv. →</button>
            </div>
          </div>
        )}
      </div>

      {/* Side Panel */}
      {selectedDossier && (
        <DossierPanel
          dossier={selectedDossier}
          onClose={() => setSelectedDossier(null)}
        />
      )}
    </div>
  );
}

// ─── Tab 3 : Scores ───────────────────────────────────────────────────────────

function TabScores() {
  const [loading, setLoading] = useState(true);
  const [scores, setScores] = useState([]);
  const [total, setTotal] = useState(0);
  const [filterRisque, setFilterRisque] = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await assureurAPI.getScores({
        ...(filterRisque && { niveau_risque: filterRisque }),
        limit: 100,
      });
      setScores(res.data.scores || []);
      setTotal(res.data.total || 0);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [filterRisque]);

  useEffect(() => { load(); }, [load]);

  // Répartition locale
  const repartition = scores.reduce((acc, s) => {
    const n = s.niveau_risque || 'unknown';
    acc[n] = (acc[n] || 0) + 1;
    return acc;
  }, {});
  const totalScored = scores.length;

  const riskLevels = [
    { key: 'low',      label: 'Faible',   color: '#4DFFB4' },
    { key: 'medium',   label: 'Modéré',   color: '#FFB347' },
    { key: 'high',     label: 'Élevé',    color: '#FF8800' },
    { key: 'critical', label: 'Critique', color: '#FF4466' },
  ];

  const avgScore = scores.length > 0
    ? (scores.reduce((s, x) => s + (x.score_global || 0), 0) / scores.length)
    : 0;

  const topNiveau = riskLevels.reduce((top, r) =>
    (repartition[r.key] || 0) > (repartition[top?.key] || -1) ? r : top,
    riskLevels[0]
  );

  return (
    <div>
      {/* Résumé */}
      <div className="asr-section" style={{ marginBottom: 20 }}>
        <div className="asr-section-header">
          <h2 className="asr-section-title">Répartition des niveaux de risque</h2>
          <span className="asr-section-count">{totalScored} scores</span>
        </div>
        <div className="asr-risque-grid">
          <ScoreGauge score={avgScore} niveau={topNiveau?.key} />
          <div style={{ padding: '10px 0' }}>
            <div className="asr-repartition">
              {riskLevels.map(r => {
                const count = repartition[r.key] || 0;
                const pct = totalScored > 0 ? Math.round((count / totalScored) * 100) : 0;
                return (
                  <div key={r.key} className="asr-risk-row">
                    <div className="asr-risk-info">
                      <span className="asr-risk-name">
                        <span className="asr-risk-dot" style={{ background: r.color }} />
                        {r.label}
                      </span>
                      <span className="asr-risk-count">{count}</span>
                    </div>
                    <div className="asr-risk-bar-bg">
                      <div className="asr-risk-bar-fill"
                        style={{ width: `${pct}%`, background: r.color }} />
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Liste des scores */}
      <div className="asr-section">
        <div className="asr-section-header">
          <h2 className="asr-section-title">Détail des scores</h2>
          <div style={{ display: 'flex', gap: 8 }}>
            <select
              className="asr-filter-select"
              value={filterRisque}
              onChange={e => setFilterRisque(e.target.value)}
            >
              <option value="">Tous les niveaux</option>
              <option value="low">Faible</option>
              <option value="medium">Modéré</option>
              <option value="high">Élevé</option>
              <option value="critical">Critique</option>
            </select>
          </div>
        </div>

        {loading ? (
          <div className="asr-loading"><div className="asr-spinner" /><span>Chargement…</span></div>
        ) : scores.length === 0 ? (
          <div className="asr-empty">
            <span className="asr-empty-icon">📊</span>
            <span className="asr-empty-text">Aucun score disponible</span>
            <span className="asr-empty-sub">Les scores apparaîtront après l'analyse IA des dossiers</span>
          </div>
        ) : (
          <div className="asr-scores-list">
            {scores.map((s, i) => {
              const color = NIVEAU_COLORS[s.niveau_risque] || '#00D4FF';
              return (
                <div key={s.id_score} className="asr-score-item" style={{ animationDelay: `${i * 0.03}s` }}>
                  <div className="asr-score-item-info">
                    <div className="asr-score-item-name">{s.entreprise_nom}</div>
                    <div className="asr-score-item-meta">
                      {s.entreprise_secteur && `${s.entreprise_secteur} · `}
                      Dossier #{s.dossier_id} · {formatDate(s.calculated_at)}
                    </div>
                  </div>
                  <div className="asr-score-item-bars">
                    <div className="asr-mini-bar">
                      <span className="asr-mini-bar-label">Quest.</span>
                      <div className="asr-mini-bar-bg">
                        <div className="asr-mini-bar-fill"
                          style={{ width: `${s.score_questionnaire}%`, background: '#00D4FF' }} />
                      </div>
                      <span className="asr-mini-bar-val">{s.score_questionnaire?.toFixed(0)}</span>
                    </div>
                    <div className="asr-mini-bar">
                      <span className="asr-mini-bar-label">Docs</span>
                      <div className="asr-mini-bar-bg">
                        <div className="asr-mini-bar-fill"
                          style={{ width: `${s.score_document}%`, background: '#9B8FFF' }} />
                      </div>
                      <span className="asr-mini-bar-val">{s.score_document?.toFixed(0)}</span>
                    </div>
                  </div>
                  <div className="asr-score-item-global">
                    <div className="asr-score-item-global-val" style={{ color }}>
                      {s.score_global?.toFixed(1)}
                    </div>
                    <div className="asr-score-item-global-label">/ 100</div>
                  </div>
                  <RiskBadge niveau={s.niveau_risque} />
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Tab 4 : Devis ────────────────────────────────────────────────────────────

function TabDevis() {
  const [loading, setLoading] = useState(true);
  const [devisList, setDevisList] = useState([]);
  const [total, setTotal] = useState(0);
  const [filterStatus, setFilterStatus] = useState('en_attente');
  const [confirm, setConfirm] = useState(null);   // { type: 'valider'|'rejeter', devis }
  const [processing, setProcessing] = useState(false);
  const [toast, setToast] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await assureurAPI.getDevis({
        ...(filterStatus && { status: filterStatus }),
        limit: 100,
      });
      setDevisList(res.data.devis || []);
      setTotal(res.data.total || 0);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [filterStatus]);

  useEffect(() => { load(); }, [load]);

  const showToast = (msg, ok = true) => {
    setToast({ msg, ok });
    setTimeout(() => setToast(null), 3000);
  };

  const handleAction = async () => {
    if (!confirm) return;
    setProcessing(true);
    try {
      if (confirm.type === 'valider') {
        await assureurAPI.validerDevis(confirm.devis.id_devis);
        showToast('✅ Devis validé avec succès');
      } else {
        await assureurAPI.rejeterDevis(confirm.devis.id_devis);
        showToast('❌ Devis rejeté', false);
      }
      setConfirm(null);
      load();
    } catch (e) {
      showToast('Erreur lors du traitement', false);
    } finally {
      setProcessing(false);
    }
  };

  return (
    <div>
      {/* Toast */}
      {toast && (
        <div style={{
          position: 'fixed', top: 20, right: 20, zIndex: 400,
          padding: '12px 20px', borderRadius: 8,
          background: toast.ok ? 'rgba(77,255,180,0.1)' : 'rgba(255,68,102,0.1)',
          border: `1px solid ${toast.ok ? 'rgba(77,255,180,0.3)' : 'rgba(255,68,102,0.3)'}`,
          color: toast.ok ? '#4DFFB4' : '#FF4466',
          fontSize: 13, fontWeight: 600,
          animation: 'fadeUp 0.2s ease',
        }}>
          {toast.msg}
        </div>
      )}

      <div className="asr-section">
        <div className="asr-section-header">
          <h2 className="asr-section-title">Validation des devis</h2>
          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
            <span className="asr-section-count">{total} devis</span>
            <select
              className="asr-filter-select"
              value={filterStatus}
              onChange={e => setFilterStatus(e.target.value)}
            >
              <option value="en_attente">En attente</option>
              <option value="validé">Validés</option>
              <option value="rejeté">Rejetés</option>
              <option value="">Tous</option>
            </select>
          </div>
        </div>

        {loading ? (
          <div className="asr-loading"><div className="asr-spinner" /><span>Chargement…</span></div>
        ) : devisList.length === 0 ? (
          <div className="asr-empty" style={{ padding: 48 }}>
            <span className="asr-empty-icon">
              {filterStatus === 'en_attente' ? '🎉' : '📋'}
            </span>
            <span className="asr-empty-text">
              {filterStatus === 'en_attente'
                ? 'Aucun devis en attente — tout est traité !'
                : 'Aucun devis dans cette catégorie'}
            </span>
          </div>
        ) : (
          <div className="asr-devis-grid">
            {devisList.map((d, i) => {
              const color = NIVEAU_COLORS[d.niveau_risque] || '#00D4FF';
              const isPending = d.status === 'en_attente' || d.status === 'draft';
              return (
                <div key={d.id_devis} className="asr-devis-card"
                  style={{ animationDelay: `${i * 0.05}s` }}>
                  <div className="asr-devis-card-top">
                    <div>
                      <div className="asr-devis-card-title">{d.entreprise_nom}</div>
                      <div className="asr-devis-card-sub">
                        {d.entreprise_secteur && `${d.entreprise_secteur} · `}
                        Dossier #{d.dossier_id}
                      </div>
                    </div>
                    <StatusBadge status={d.status} />
                  </div>

                  <div className="asr-devis-prime">
                    <span className="asr-devis-prime-label">Prime proposée</span>
                    <span className="asr-devis-prime-value">{formatPrime(d.prime)}</span>
                  </div>

                  <div className="asr-devis-score-row">
                    <span className="asr-devis-score-label">Score de risque</span>
                    <span className="asr-devis-score-val" style={{ color }}>
                      {d.score_global?.toFixed(1)} / 100
                    </span>
                    <RiskBadge niveau={d.niveau_risque} />
                  </div>

                  {isPending && (
                    <div className="asr-devis-card-actions">
                      <button
                        className="asr-btn asr-btn--success"
                        onClick={() => setConfirm({ type: 'valider', devis: d })}
                      >
                        ✓ Valider
                      </button>
                      <button
                        className="asr-btn asr-btn--danger"
                        onClick={() => setConfirm({ type: 'rejeter', devis: d })}
                      >
                        ✕ Rejeter
                      </button>
                    </div>
                  )}

                  {!isPending && (
                    <div style={{ fontSize: 11, color: 'var(--c-text2)' }}>
                      Traité le {formatDate(d.created_at)}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Confirm modal */}
      {confirm && (
        <ConfirmModal
          icon={confirm.type === 'valider' ? '✅' : '❌'}
          title={confirm.type === 'valider' ? 'Valider ce devis ?' : 'Rejeter ce devis ?'}
          text={
            confirm.type === 'valider'
              ? `Vous allez valider le devis de ${confirm.devis.entreprise_nom} pour une prime de ${formatPrime(confirm.devis.prime)}.`
              : `Vous allez rejeter le devis de ${confirm.devis.entreprise_nom}. Cette action est définitive.`
          }
          confirmLabel={confirm.type === 'valider' ? '✓ Confirmer la validation' : '✕ Confirmer le rejet'}
          confirmClass={confirm.type === 'valider' ? 'asr-btn--success' : 'asr-btn--danger'}
          onConfirm={handleAction}
          onCancel={() => setConfirm(null)}
        />
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ═══════════════════════════════════════════════════════════════════════════════

const NAV_ITEMS = [
  { icon: '⬡', label: 'Vue d\'ensemble', id: 'overview' },
  { icon: '◈', label: 'Dossiers',         id: 'dossiers' },
  { icon: '◉', label: 'Scores de risque', id: 'scores' },
  { icon: '▣', label: 'Valider devis',    id: 'devis', badge: true },
];

export default function Assureur() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [activeTab, setActiveTab] = useState(searchParams.get('tab') || 'overview');
  const [collapsed, setCollapsed] = useState(false);
  const [stats, setStats] = useState(null);
  const [statsLoading, setStatsLoading] = useState(true);

  useEffect(() => {
    const tab = searchParams.get('tab');
    if (tab) setActiveTab(tab);
  }, [searchParams]);

  useEffect(() => {
    assureurAPI.getStats()
      .then(r => setStats(r.data))
      .catch(console.error)
      .finally(() => setStatsLoading(false));
  }, []);

  const handleLogout = () => { logout(); navigate('/login'); };

  if (!user) return null;

  const renderTab = () => {
    switch (activeTab) {
      case 'overview': return <TabOverview stats={stats} onTabChange={setActiveTab} />;
      case 'dossiers': return <TabDossiers />;
      case 'scores':   return <TabScores />;
      case 'devis':    return <TabDevis />;
      default:         return <TabOverview stats={stats} onTabChange={setActiveTab} />;
    }
  };

  const currentNav = NAV_ITEMS.find(n => n.id === activeTab);
  const devisCount = stats?.devis_a_valider || 0;

  return (
    <div className={`asr ${collapsed ? 'asr--collapsed' : 'asr--open'}`}>
      {/* ── Sidebar ── */}
      <aside className="asr-sidebar">
        <div className="asr-sidebar-top">
          {/* Logo */}
          <div className="asr-logo">
            <svg width="28" height="28" viewBox="0 0 36 36" fill="none">
              <polygon points="18,2 34,10 34,26 18,34 2,26 2,10"
                stroke="#00D4FF" strokeWidth="1.5" fill="none" />
              <circle cx="18" cy="18" r="4" fill="#00D4FF" />
            </svg>
            {!collapsed && (
              <span className="asr-logo-text">CYBER<strong>INSURE</strong></span>
            )}
          </div>

          {/* User pill */}
          {!collapsed && (
            <div className="asr-user-pill">
              <div className="asr-user-avatar">
                {user.email?.[0]?.toUpperCase()}
              </div>
              <div className="asr-user-info">
                <span className="asr-user-email">{user.email}</span>
                <span className="asr-user-role">Assureur</span>
              </div>
            </div>
          )}

          {/* Nav */}
          <nav className="asr-nav">
            {NAV_ITEMS.map(item => (
              <button
                key={item.id}
                className={`asr-nav-item ${activeTab === item.id ? 'asr-nav-item--active' : ''}`}
                onClick={() => {}}
                title={collapsed ? item.label : ''}
              >
                <span className="asr-nav-icon">{item.icon}</span>
                {!collapsed && <span className="asr-nav-label">{item.label}</span>}
                {!collapsed && item.badge && devisCount > 0 && (
                  <span className="asr-nav-badge">{devisCount}</span>
                )}
                {activeTab === item.id && (
                  <div className="asr-nav-indicator" />
                )}
              </button>
            ))}
          </nav>
        </div>

        <div className="asr-sidebar-bottom">
          <button className="asr-logout" onClick={handleLogout}>
            <svg viewBox="0 0 20 20" fill="none">
              <path d="M13 4l4 6-4 6M17 10H7M10 4H4a1 1 0 00-1 1v10a1 1 0 001 1h6"
                stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
            {!collapsed && <span>Déconnexion</span>}
          </button>
        </div>
      </aside>

      {/* ── Main ── */}
      <main className="asr-main">
        {/* Header */}
        <header className="asr-header">
          <div className="asr-header-left">
            <button className="asr-toggle" onClick={() => setCollapsed(c => !c)}>
              <span /><span /><span />
            </button>
            <div>
              <h1 className="asr-page-title">
                Tableau de bord
              </h1>
              <p className="asr-page-sub">
                Connecté en tant que <span>Assureur</span>
              </p>
            </div>
          </div>
          <div className="asr-header-right">
            <div className="asr-status">
              <span className="asr-status-dot" />
              <span>SYSTÈME OPÉRATIONNEL</span>
            </div>
            <div className="asr-clock">
              {new Date().toLocaleDateString('fr-FR', {
                day: '2-digit', month: '2-digit', year: 'numeric',
              })}
            </div>
          </div>
        </header>

        {/* Content */}
        <div className="asr-content">
          {renderTab()}
        </div>
      </main>
    </div>
  );
}
